#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        if (N % 2 == 0) {
            printf("Chef\n");
        } else {
            printf("Misha\n");
        }
    }
    return 0;
}

